+func TestRuleSet_Disable_UnknownRule(t *testing.T) {
+	t.Parallel()
+	rs := DefaultRuleSet()
+
+	// Should not panic for unknown rule ID
+	rs.Disable(RuleID("nonexistent-rule"))
+}
